46	function setUserRole() {
47	    const headerElement = document.querySelector('.dt-emc-header');
48	
49	    if (!headerElement) {
50	        console.log('Element with class dt-header not found');
51	        return;
52	    }
53	
54	    const audType = headerElement.getAttribute('data-audtype');
55	    const lldisplay = headerElement.getAttribute('data-lldisplay');
56	
57	    let userRole = '';
58	
59	    switch (audType) {
60	        case 'Guest':
61	            userRole = 'Guest only';
62	            break;
63	        case 'Internal':
64	            userRole = 'Internal';
65	            break;
66	        case 'Customer':
67	            userRole = lldisplay === 'true' ? 'Customer with LH' : 'Customer no LH';
68	            break;
69	        case 'Partner':
70	            userRole = lldisplay === 'true' ? 'Partner with LH' : 'Partner no LH';
71	            break;
72	        default:
73	            console.log('Unknown audType:', audType);
74	            return;
75	    }
76	
77	    if (typeof Dell.Metrics.sc === 'undefined') {
78	            Dell.Metrics.sc = {};
79	        }
80	
81	    Dell.Metrics.sc.userrole = userRole;
82	
83	    console.log('User role set to:', userRole);
84	}
85	
86	if (document.readyState === 'loading') {
87	    document.addEventListener('DOMContentLoaded', setUserRole);
88	} else {
89	    // DOM is already loaded
90	    setUserRole();
91	}
92	</script>
